import { Route } from './types';

export function routeFor(path: string): Route | null {
  if (path === '/') {
    return { title: 'Acme Dashboard Home', body: 'Welcome to Acme' };
  }
  if (path === '/pricing') {
    return { title: 'Plans & Pricing', body: 'Starter: $9/mo' };
  }
  if (path === '/about') {
    return { title: 'About Acme', body: 'Founded 2019' };
  }
  if (path === '/stats') {
    return { title: 'Usage Statistics', body: 'Daily Active Users' };
  }
  return null;
}

import { Stats, FormattedStats } from './types';

